def search_postmortem_library(
    failure_category: str | None = None,
    affected_system: str | None = None,
    root_cause_tag: str | None = None,
    severity: str | None = None,
    date_from: str | None = None,
    repeat_only: bool = False,
) -> list[dict]:
    filters = {}
    if failure_category:
        filters["failure_category"] = failure_category
    if affected_system:
        filters["affected_system"] = affected_system
    if root_cause_tag:
        filters["root_cause_tags"] = {"contains": root_cause_tag}
    if severity:
        filters["severity"] = severity
    if date_from:
        filters["date"] = {"gte": date_from}
    if repeat_only:
        filters["repeat_failure"] = True
    return query_notion_database(POSTMORTEM_DB_ID, filters)

