from datetime import datetime, timedelta

def generate_weekly_digest(library_query_fn, week_start: datetime) -> str:
    week_end = week_start + timedelta(days=7)
    new_pms = library_query_fn(date_from=week_start.isoformat(), date_to=week_end.isoformat())
    overdue_actions = get_overdue_action_items(as_of=week_end)
    repeat_failures = library_query_fn(
        repeat_only=True,
        date_from=(week_end - timedelta(days=30)).isoformat(),
    )
    sections = []
    sections.append(f"## Incident Digest -- Week of {week_start.strftime('%Y-%m-%d')}")
    if new_pms:
        sections.append("### New Postmortems This Week")
        for pm in new_pms:
            sections.append(format_pm_summary(pm))
    if overdue_actions:
        sections.append("### Action Items Overdue")
        for ai in overdue_actions:
            sections.append(f"- {ai['id']}: {ai['title']} (owner: {ai['owner']}) -- {ai['days_overdue']} days overdue")
    if repeat_failures:
        sections.append("### Repeat Failures This Month")
        for pm in repeat_failures:
            sections.append(format_repeat_failure(pm))
    return "\n\n".join(sections)

from collections import Counter

def quarterly_pattern_analysis(postmortems: list[dict]) -> dict:
    category_counts = Counter()
    root_cause_counts = Counter()
    system_counts = Counter()
    time_to_detect = []
    for pm in postmortems:
        for cat in pm.get("failure_categories", []):
            category_counts[cat] += 1
        for tag in pm.get("root_cause_tags", []):
            root_cause_counts[tag] += 1
        system_counts[pm.get("affected_system", "unknown")] += 1
        if pm.get("time_to_detect_minutes"):
            time_to_detect.append(pm["time_to_detect_minutes"])
    return {
        "top_failure_categories": category_counts.most_common(5),
        "top_root_cause_tags": root_cause_counts.most_common(5),
        "most_affected_systems": system_counts.most_common(5),
        "mean_time_to_detect_min": sum(time_to_detect) / len(time_to_detect) if time_to_detect else None,
        "p90_time_to_detect_min": sorted(time_to_detect)[int(len(time_to_detect) * 0.9)] if time_to_detect else None,
        "repeat_failure_count": sum(1 for pm in postmortems if pm.get("repeat_failure")),
        "repeat_failure_rate": sum(1 for pm in postmortems if pm.get("repeat_failure")) / len(postmortems) if postmortems else 0,
    }
